import React from 'react';

const stats = [
  { label: 'Total Students', value: '1,247', color: '#3498db' },
  { label: 'Active Students', value: '892', color: '#27ae60' },
  { label: 'Total Companies', value: '156', color: '#e74c3c' },
  { label: 'Placement Rate', value: '78.5%', color: '#f39c12' },
];

const activityGroups = [
  {
    title: 'New Students',
    color: '#3498db',
    items: [
      'Rahul Kumar - Computer Science',
      'Priya Sharma - Information Technology',
      'Amit Patel - Computer Science',
      'Neha Gupta - Electronics Engineering',
    ],
  },
  {
    title: 'New Companies',
    color: '#27ae60',
    items: [
      'Tech Solutions Inc - Software Development',
      'Global Systems - IT Services',
      'Data Analytics Pro - Data Science',
      'CloudTech Industries - Cloud Computing',
    ],
  },
];

const statCardStyle = (backgroundColor) => ({
  backgroundColor,
  padding: '40px',
  borderRadius: '15px',
  color: 'white',
  textAlign: 'center',
  boxShadow: '0 10px 20px rgba(0,0,0,0.2)',
});

const Dashboard = () => {
  return (
    <div
      style={{
        padding: '30px',
        backgroundColor: '#f5f5f5',
        minHeight: '100vh',
      }}
    >
      <h1
        style={{
          fontSize: '42px',
          color: '#2c3e50',
          textAlign: 'center',
          marginBottom: '40px',
          fontWeight: 'bold',
        }}
      >
        PLACEMENT DASHBOARD
      </h1>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: '30px',
          maxWidth: '1200px',
          margin: '0 auto',
        }}
      >
        {stats.map((stat) => (
          <div key={stat.label} style={statCardStyle(stat.color)}>
            <h2 style={{ margin: '0 0 15px 0', fontSize: '20px' }}>{stat.label}</h2>
            <p style={{ margin: 0, fontSize: '48px', fontWeight: 'bold' }}>{stat.value}</p>
          </div>
        ))}
      </div>

      <div
        style={{
          backgroundColor: 'white',
          padding: '40px',
          borderRadius: '15px',
          marginTop: '40px',
          boxShadow: '0 5px 15px rgba(0,0,0,0.1)',
        }}
      >
        <h2 style={{ margin: '0 0 25px 0', fontSize: '28px', color: '#2c3e50' }}>Recent Activity</h2>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
            gap: '30px',
          }}
        >
          {activityGroups.map((group) => (
            <div key={group.title}>
              <h3 style={{ margin: '0 0 15px 0', color: group.color, fontSize: '20px' }}>{group.title}</h3>
              <ul style={{ margin: 0, paddingLeft: '20px', color: '#555', lineHeight: '1.8' }}>
                {group.items.map((item) => (
                  <li key={item}>{item}</li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
